1	/** A live cell's position on the infinite grid, as [x, y] coordinates. */
2	export type Cell = [number, number];
3	
4	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
5	  [-1, -1], [0, -1], [1, -1],
6	  [-1,  0],          [1,  0],
7	  [-1,  1], [0,  1], [1,  1],
8	];
9	
10	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
11	
12	const neighborsOf = ([x, y]: Cell): Cell[] =>
13	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
14	
15	const countLiveNeighbors = (cell: Cell, liveKeys: Set<string>): number =>
16	  neighborsOf(cell).filter((neighbor) => liveKeys.has(cellKey(neighbor))).length;
17	
18	const deadNeighborsOf = (liveCells: Cell[], liveKeys: Set<string>): Cell[] => {
19	  const dead = new Map<string, Cell>();
20	  for (const live of liveCells) {
21	    for (const neighbor of neighborsOf(live)) {
22	      const key = cellKey(neighbor);
23	      if (!liveKeys.has(key)) dead.set(key, neighbor);
24	    }
25	  }
26	  return [...dead.values()];
27	};
28	
29	/**
30	 * Computes the live cells of the next generation of Conway's Game of Life
31	 * from the current set of live cells.
32	 */
33	export function nextGeneration(liveCells: Cell[]): Cell[] {
34	  const liveKeys = new Set(liveCells.map(cellKey));
35	  const survivors = liveCells.filter((cell) => {
36	    const n = countLiveNeighbors(cell, liveKeys);
37	    return n >= 2 && n <= 3;
38	  });
39	  const births = deadNeighborsOf(liveCells, liveKeys)
40	    .filter((cell) => countLiveNeighbors(cell, liveKeys) === 3);
41	  return [...survivors, ...births];
42	}
