const survives = (liveNeighborCount: number): boolean =>
  liveNeighborCount === 2 || liveNeighborCount === 3;

const isBorn = (liveNeighborCount: number): boolean =>
  liveNeighborCount === 3;

/**
 * Computes the live cells of the next generation of Conway's Game of Life
 * from the current set of live cells.
 */
export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveKeys = new Set(liveCells.map(cellKey));
  const survivors = liveCells.filter((cell) =>
    survives(countLiveNeighbors(cell, liveKeys))
  );
  const births = deadNeighborsOf(liveCells, liveKeys).filter((cell) =>
    isBorn(countLiveNeighbors(cell, liveKeys))
  );
  return [...survivors, ...births];
}
